import{_ as t,o as a,c as e,a4 as r}from"./chunks/framework.Bz0lZ1uX.js";const f=JSON.parse('{"title":"人物素材","description":"","frontmatter":{},"headers":[],"relativePath":"materials/人物素材/index.md","filePath":"materials/人物素材/index.md","lastUpdated":null}'),l={name:"materials/人物素材/index.md"},s=r('<h1 id="人物素材" tabindex="-1">人物素材 <a class="header-anchor" href="#人物素材" aria-label="Permalink to &quot;人物素材&quot;">​</a></h1><p>人物素材是议论文写作中最常用的论据类型之一。通过典型人物的事迹，可以有力地支撑论点。</p><h2 id="素材分类导航" tabindex="-1">素材分类导航 <a class="header-anchor" href="#素材分类导航" aria-label="Permalink to &quot;素材分类导航&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">分类</th><th style="text-align:left;">描述</th><th style="text-align:center;">素材数量</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/materials/人物素材/科学家/">科学家</a></td><td style="text-align:left;">在科学领域做出杰出贡献的研究者</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/企业家与发明家/">企业家与发明家</a></td><td style="text-align:left;">推动产业变革的企业家和技术发明者</td><td style="text-align:center;">3</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/青年榜样/">青年榜样</a></td><td style="text-align:left;">展现当代青年精神的典型人物</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/艺术家与文化工作者/">艺术家与文化工作者</a></td><td style="text-align:left;">在艺术与文化传播领域有突出贡献者</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/社会活动家/">社会活动家</a></td><td style="text-align:left;">推动社会进步与公平正义的先锋</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:left;"><a href="/materials/人物素材/基层干部/">基层干部</a></td><td style="text-align:left;">在平凡岗位上展现责任担当的基层工作者</td><td style="text-align:center;">1</td></tr></tbody></table><hr><h2 id="科学家" tabindex="-1">科学家 <a class="header-anchor" href="#科学家" aria-label="Permalink to &quot;科学家&quot;">​</a></h2><h3 id="中村修二-蓝色led之父" tabindex="-1"><a href="/materials/人物素材/科学家/中村修二.html">中村修二</a> - 蓝色LED之父 <a class="header-anchor" href="#中村修二-蓝色led之父" aria-label="Permalink to &quot;[中村修二](/materials/人物素材/科学家/中村修二) - 蓝色LED之父&quot;">​</a></h3><p><strong>标签</strong>: #科学家 #诺贝尔奖 #坚持不懈 #专注 #科技报国 #平凡中的伟大</p><p><strong>事迹</strong>: 日裔美籍电子工程学家，在众人不看好的氮化镓技术路线上独自攻坚，研制出高亮度蓝色LED，荣获2014年诺贝尔物理学奖。</p><p><strong>适用主题</strong>: 坚持、创新、专注、科技报国、平凡中的伟大</p><hr><h2 id="企业家与发明家" tabindex="-1">企业家与发明家 <a class="header-anchor" href="#企业家与发明家" aria-label="Permalink to &quot;企业家与发明家&quot;">​</a></h2><h3 id="威廉·勒梅修里尔-工程师良知的守护者" tabindex="-1"><a href="/materials/人物素材/企业家与发明家/威廉·勒梅修里尔.html">威廉·勒梅修里尔</a> - 工程师良知的守护者 <a class="header-anchor" href="#威廉·勒梅修里尔-工程师良知的守护者" aria-label="Permalink to &quot;[威廉·勒梅修里尔](/materials/人物素材/企业家与发明家/威廉·勒梅修里尔) - 工程师良知的守护者&quot;">​</a></h3><p><strong>标签</strong>: #工程师 #责任担当 #诚信 #勇气 #职业道德 #良知</p><p><strong>事迹</strong>: 美国著名结构工程师，发现花旗大厦存在倒塌风险后，毅然选择向公众坦白并连夜组织抢险加固，挽救了成千上万人的生命。</p><p><strong>适用主题</strong>: 责任担当、诚信、勇气、职业道德、良知、知错能改</p><h3 id="弗雷德里克·图多·戈里-人工制冷时代的开创者" tabindex="-1"><a href="/materials/人物素材/企业家与发明家/弗雷德里克·图多·戈里.html">弗雷德里克·图多·戈里</a> - 人工制冷时代的开创者 <a class="header-anchor" href="#弗雷德里克·图多·戈里-人工制冷时代的开创者" aria-label="Permalink to &quot;[弗雷德里克·图多·戈里](/materials/人物素材/企业家与发明家/弗雷德里克·图多·戈里) - 人工制冷时代的开创者&quot;">​</a></h3><p><strong>标签</strong>: #发明家 #创新 #勇气 #打破垄断 #科技改变生活</p><p><strong>事迹</strong>: 19世纪美国发明家，潜心研发人工制冰技术，打破了天然冰业巨头的垄断，开启了人工制冷的新纪元。</p><p><strong>适用主题</strong>: 创新、勇气、打破垄断、科技改变生活、挑战权威、时代变革</p><h3 id="梁文峰-deepseek创始人与ai技术自立突围者" tabindex="-1"><a href="/materials/人物素材/企业家与发明家/梁文峰.html">梁文峰</a> - DeepSeek创始人与AI技术自立突围者 <a class="header-anchor" href="#梁文峰-deepseek创始人与ai技术自立突围者" aria-label="Permalink to &quot;[梁文峰](/materials/人物素材/企业家与发明家/梁文峰) - DeepSeek创始人与AI技术自立突围者&quot;">​</a></h3><p><strong>标签</strong>: #企业家 #科学家 #远见 #创新 #科技自立 #家国情怀</p><p><strong>事迹</strong>: 中国&quot;80后&quot;科学家、企业家，创立DeepSeek，推出V3、R1、V4等重磅AI模型，以极低成本打破硅谷闭源模型垄断，优先适配国产算力平台。</p><p><strong>适用主题</strong>: 远见、创新、科技自立、家国情怀、战略定力</p><hr><h2 id="青年榜样" tabindex="-1">青年榜样 <a class="header-anchor" href="#青年榜样" aria-label="Permalink to &quot;青年榜样&quot;">​</a></h2><h3 id="paper2gal开发者-大学生跨界创新的典范" tabindex="-1"><a href="/materials/人物素材/青年榜样/Paper2Gal开发者.html">Paper2Gal开发者</a> - 大学生跨界创新的典范 <a class="header-anchor" href="#paper2gal开发者-大学生跨界创新的典范" aria-label="Permalink to &quot;[Paper2Gal开发者](/materials/人物素材/青年榜样/Paper2Gal开发者) - 大学生跨界创新的典范&quot;">​</a></h3><p><strong>标签</strong>: #大学生 #青年榜样 #创新 #跨界融合 #知识共享 #青年担当</p><p><strong>事迹</strong>: 佛山大学大三学生，自学AI技术开发免费工具Paper2Gal，将学术论文转换为二次元互动对话游戏，以纯粹共享初衷火遍科研圈。</p><p><strong>适用主题</strong>: 创新、跨界融合、知识共享、青年担当、匠心与纯粹</p><hr><h2 id="艺术家与文化工作者" tabindex="-1">艺术家与文化工作者 <a class="header-anchor" href="#艺术家与文化工作者" aria-label="Permalink to &quot;艺术家与文化工作者&quot;">​</a></h2><h3 id="泰奥·杨森-风力仿生兽的造物主" tabindex="-1"><a href="/materials/人物素材/艺术家与文化工作者/泰奥·杨森.html">泰奥·杨森</a> - 风力仿生兽的造物主 <a class="header-anchor" href="#泰奥·杨森-风力仿生兽的造物主" aria-label="Permalink to &quot;[泰奥·杨森](/materials/人物素材/艺术家与文化工作者/泰奥·杨森) - 风力仿生兽的造物主&quot;">​</a></h3><p><strong>标签</strong>: #艺术家 #坚持 #创新 #跨界融合 #人与自然 #匠心</p><p><strong>事迹</strong>: 荷兰动能艺术家，被誉为&quot;现代达芬奇&quot;，用三十年时间创造风力驱动的&quot;仿生兽&quot;，让科技与艺术在自然风中完美融合。</p><p><strong>适用主题</strong>: 坚持、创新、跨界融合、人与自然、匠心、科技与艺术</p><hr><h2 id="社会活动家" tabindex="-1">社会活动家 <a class="header-anchor" href="#社会活动家" aria-label="Permalink to &quot;社会活动家&quot;">​</a></h2><h3 id="马丁·路德·金-非暴力抗争的民权领袖" tabindex="-1"><a href="/materials/人物素材/社会活动家/马丁·路德·金.html">马丁·路德·金</a> - 非暴力抗争的民权领袖 <a class="header-anchor" href="#马丁·路德·金-非暴力抗争的民权领袖" aria-label="Permalink to &quot;[马丁·路德·金](/materials/人物素材/社会活动家/马丁·路德·金) - 非暴力抗争的民权领袖&quot;">​</a></h3><p><strong>标签</strong>: #社会活动家 #平等 #正义 #信念 #梦想 #勇气 #非暴力抗争</p><p><strong>事迹</strong>: 美国民权运动领袖，1963年发表《我有一个梦想》演说，以非暴力抗争推动《民权法案》诞生，诺贝尔和平奖得主。</p><p><strong>适用主题</strong>: 平等、正义、信念、梦想、勇气、非暴力抗争</p><hr><h2 id="基层干部" tabindex="-1">基层干部 <a class="header-anchor" href="#基层干部" aria-label="Permalink to &quot;基层干部&quot;">​</a></h2><h3 id="马科长-基层干部的责任担当与智慧抉择" tabindex="-1"><a href="/materials/人物素材/基层干部/马科长.html">马科长</a> - 基层干部的责任担当与智慧抉择 <a class="header-anchor" href="#马科长-基层干部的责任担当与智慧抉择" aria-label="Permalink to &quot;[马科长](/materials/人物素材/基层干部/马科长) - 基层干部的责任担当与智慧抉择&quot;">​</a></h3><p><strong>标签</strong>: #基层干部 #责任担当 #利义之辨 #抉择智慧 #初心与坚守</p><p><strong>事迹</strong>: 河北武安市发改局工业科科长，面对央视采访以特殊方式应对，被重新解读为在&quot;去产能&quot;激流中为地方产业转型和工人生计赢得缓冲空间的智慧担当。</p><p><strong>适用主题</strong>: 责任担当、利义之辨、民心至上、抉择智慧、初心与坚守、平衡之道</p><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ol><li>选择与论点高度相关的人物素材</li><li>注意素材的时效性，适当使用当代人物</li><li>人物事迹要准确，不可道听途说</li><li>结合具体细节，增强说服力</li><li>一个人物可从多个角度解读，灵活使用</li></ol>',51),n=[s];function o(i,h,d,p,g,c){return a(),e("div",null,n)}const u=t(l,[["render",o]]);export{f as __pageData,u as default};
